const messages = items.map(item => item.json);
const triggerId = $('WAHA Webhook').first().json.body.payload.id;
const latestMessageId = messages[0]?.id?._serialized || messages[0]?.id;
const cleanLatest = latestMessageId.includes('_') ? latestMessageId.split('_').pop() : latestMessageId;
const cleanTrigger = triggerId.includes('_') ? triggerId.split('_').pop() : triggerId;

if (cleanLatest !== cleanTrigger) { return []; }

const combinedText = messages.filter(m => m.fromMe === false).slice(0, 5).reverse().map(m => m.body).join("\n");

items[0].json.final_input = combinedText;
return [items[0]];

const webhookData = $('WAHA Webhook').item.json;
const payload = webhookData.body.payload;
if (!payload || !payload.from || payload.fromMe) return [];

const combinedText = $json.final_input || payload.body || "";
const phone = payload.from;
let mediaPath = null;

if (payload.media?.url) {
  const fullUrl = payload.media.url;
  const pathStart = fullUrl.indexOf('/api/');
  if (pathStart !== -1) mediaPath = fullUrl.substring(pathStart);
}

let isAudio = false;
let messageText = combinedText;

if (payload.hasMedia) {
  const mediaType = payload._data?.type;
  if (mediaType === 'ptt' || mediaType === 'audio') {
    isAudio = true;
    messageText = "[AUDIO]"; 
  } else if (mediaType === 'image') {
    messageText = combinedText !== "" ? combinedText : "[IMAGE]";
  } else if (mediaType === 'video') {
    messageText = "[VIDEO]";
  }
}

items[0].json = { phone, messageText, isAudio, mediaPath, mediaType: payload._data?.type, mimetype: payload.media?.mimetype, messageId: payload.id };
return [items[0]];
